from lxml import etree

def process_soap_request(xml_string):
    parser = etree.XMLParser(dtd_validation=True, no_network=False, load_dtd=True)
    
    try:
        root = etree.fromstring(xml_string.encode('utf-8'), parser=parser)
    except etree.XMLSyntaxError as e:
        raise ValueError(f"Invalid XML or DTD validation failed: {e}")
    
    namespaces = {
        'soap': 'http://schemas.xmlsoap.org/soap/envelope/',
        'soapenv': 'http://schemas.xmlsoap.org/soap/envelope/'
    }
    
    body = root.find('soap:Body', namespaces)
    if body is None:
        body = root.find('soapenv:Body', namespaces)
    
    if body is None:
        raise ValueError("SOAP Body not found in the envelope")
    
    body_content = []
    for child in body:
        body_content.append(child)
    
    return {
        'envelope': root,
        'body': body,
        'body_content': body_content
    }